        // and this query would return zero results against existing documents.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 breaking change: synchronous I/O now throws by default on Cosmos.
        // Must use async APIs (ToListAsync, FirstOrDefaultAsync, etc.)
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

